VALUES
  ('optician-moex-01599', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關自覺式驗光中的散光檢查方法，下列敘述何者正確？', '["傑克森交叉圓柱鏡（JCC）不需霧視，散光鐘面圖（clockdialchart）檢查需要霧視", "JCC檢查時最小模糊圈在視網膜前，散光鐘面圖檢查時最小模糊圈在視網膜上", "JCC檢查時視標適合選用鐘面圖，散光鐘面圖檢查時，視標適合選用蜂巢亂點圖", "JCC檢查時不需要輔助鏡，散光鐘面圖檢查時需要輔助鏡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01600', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '測量受驗者近距離的瞳距，在30公分的瞳距比40公分來得小，這是因為眼球增加：', '["發散", "調視", "內聚", "縮瞳"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01601', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '以雙色測試（bichrome）或紅綠測試（red-greentest）驗證，得到自覺式驗光的初步結果，再加上+1.00D 的球面鏡霧化（fogging）之後，病人應表示何色的視標較清楚？', '["紅色", "綠色", "一樣清楚", "無法判斷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01602', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關雙眼平衡的方式，下列敘述何者正確？', '["漢佛萊斯法（Humphrissmethod）是利用遮眼棒交互遮蓋", "垂直稜鏡分離法需要偏光濾片（polaroid）來分離視標", "偏光濾片法左右眼各可以看到視標的某部分", "交替遮蓋法（alternateocclusiontest）左右眼同時看到視標"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01603', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '患者初步驗光值為-3.00DS/-0.75DC×180，利用紅、綠雙色視標進行驗光終點確認檢查；主述紅色背景的 數字較黑、較清楚，則度數應修正為下列何者？', '["-2.75DS/-0.75DC×180", "-3.00DS/-0.50DC×180", "-3.00DS/-1.00DC×180", "-3.25DS/-0.75DC×180"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01604', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '平均而言，初生嬰兒的屈光狀態較接近下列何者？', '["正視眼", "遠視+3.00D", "遠視+1.00D", "近視-1.00D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01605', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '稜鏡分離法中右眼放3ΔBU，左眼放3ΔBD在剛開始測驗時，如果上面的視標較清楚，應該如何處置？', '["右眼球面鏡片加-0.25D", "左眼球面鏡片加-0.25D", "右眼球面鏡片加+0.25D", "左眼球面鏡片加+0.25D"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01606', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '以視網膜檢影鏡檢查一眼，發現僅有球面屈光不正，而在自覺式驗光的第一次最佳球面度（firstbestvision sphere）確認後，卻無法達到理想視力，疑似有潛在散光未被檢出。檢查者將-0.25DC 散光片置入綜合驗 光儀，並以傑克森交叉圓柱鏡（JCC）確認045、090、135、180等軸度的散光度數。結果發現，在上述4 個軸度的檢查，皆是白點對齊散光軸度時視標清楚於紅點對齊散光軸度。患者的散光狀態為何？', '["散光軸度接近180", "散光軸度不穩定變化", "無明顯散光", "不規則散光"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01607', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '對品質管制作業員檢測近用視力，其工作距離為40公分。若被檢者調節力剩下1.50 D。依據調節幅度一 半原則（tentativeaddbasedonhalftheamplitudeinreserve），給予暫定加入度（tentativeADD）為下列何者？', '["+1.00D", "+1.50D", "+1.75D", "+2.50D"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01608', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受檢者有+1.50D遠視眼，在未配戴矯正眼鏡下，以負鏡片法（minuslensmethod）進行調節幅度測試。當 視標置於40公分處，逐漸加入負球面度直到-10.00D時，受檢者開始感到視標持續模糊，則該眼的調節幅 度為下列何者？', '["8.50D", "10.00D", "11.00D", "14.00D"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
